head.script:
let isPopupOpen = false; // 팝업 상태 저장 변수
scwin.olddata = '';
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    // 세션정보
    let memJson = $c.data.getMemInfo();
    scwin.sUserId = $c.data.getMemInfo("userId");
    scwin.sUserClsCd = $c.data.getMemInfo("userClsCd") == null ? "" : $c.data.getMemInfo("userClsCd");
    scwin.sClntNo = $c.data.getMemInfo("clntNo") == null ? "" : $c.data.getMemInfo("clntNo");
    scwin.sClntNm = $c.data.getMemInfo("clntNm") == null ? "" : $c.data.getMemInfo("clntNm");
    scwin.gv_loabranCd = $c.data.getMemInfo("loUpperLobranCd");
    scwin.vCurDate = $c.date.getServerDateTime();  // 서버를 기준으로 현재 날짜 반환

    scwin.params = $c.data.getParameter();
    scwin.wrkLobranCd = scwin.params.wrkLobranCd == null ? "" : scwin.params.wrkLobranCd;  //작업장
    scwin.wrkDt = scwin.params.wrkDt == null ? scwin.vCurDate : scwin.params.wrkDt;  //작업일자
    scwin.odrNo = scwin.params.odrNo == null ? "" : scwin.params.odrNo;  //오더번호
    ica_ed_wrkDt.setValue(scwin.wrkDt);
    ica_ed_wrkDt.focus();
    acb_lc_lobranCd.setValue(scwin.wrkLobranCd);
    ed_odrNo.setValue(scwin.odrNo);
    const utilOptions = [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            param3: [""],
            compID: "acb_lc_lobranCd"
        }
    ];
    await $c.data.setGauceUtil(utilOptions, function () {
        //배차점소
        acb_lc_lobranCd.setValue(scwin.gv_loabranCd);

        if (scwin.wrkLobranCd.trim() != "") {
            acb_lc_lobranCd.setValue(scwin.wrkLobranCd);
            ica_ed_wrkDt.setValue(scwin.wrkDt);
            ed_odrNo.setValue(scwin.odrNo);

            scwin.btn_retrieve_onclick();
        }
    });
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tb_searchCondition, [acb_lc_lobranCd, ica_ed_wrkDt]);
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    //dma_retrieve.useChangeInfo = false;

    var wrkDt = dma_retrieve.get("wrkDt");

    if (wrkDt == "        ") {
        dma_retrieve.set("wrkDt", "");
    }

    if ($c.gus.cfIsNull(ica_ed_wrkDt.getValue()) && $c.gus.cfIsNull(ed_odrNo.getValue()) && $c.gus.cfIsNull(ed_cntrNo.getValue())) {
        $c.win.alert("작업일자  또는 오더번호 또는 컨테이너 중 하나 이상의 조회 조건을 선택하십시오.");
        return false;
    }

    // tr_retrieve.KeyValue = "Servlet(I:IN_DS1=dma_retrieve,O:OUT_DS1=ds_out)";
    // tr_retrieve.Action = "/tn.op.transwrkindict.cntr.RetrieveProTContainerWorkIndicationCMD.do";
    // tr_retrieve.Post();
    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        if (ds_out.getRowCount() == 0) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);  //alert("조회된 데이터가 없습니다.");
        }
        else {
            let sort_options = {};
            sort_options.sortIndex = "odrNo cntrSeq wrkPathSeq wrkStpSeq";
            sort_options.sortOrder = "1 1 1 1"; // 전부 오름차순

            // 데이터리스트(ds_out) 정렬 실행
            ds_out.multisort(sort_options);
            totalRows.setValue(ds_out.getRowCount());
            gr_out.setFocusedCell(0, "odrNo");

            //Value={cntrSizCd&cntrTypCd&fullEmptyClsCd}
            for (var i = 0; i < ds_out.getRowCount(); i++) {
                ds_out.setCellData(i, "cntrTypCdInfo", ds_out.getCellData(i, "cntrSizCd") + ds_out.getCellData(i, "cntrTypCd") + ds_out.getCellData(i, "fullEmptyClsCd"));
                ds_out.modifyRowStatus(i, "R");
            }
        }
    }
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    var che = "";
    var v_isTransSaved = false;	//도어운송단계가 저장되었는지를 체크
    var v_lastRow = 0;

    if (ds_out.getModifiedIndex().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["Data"]);
        return;
    }

    let ret = $c.gus.cfValidate([gr_out]);
    if (!ret) {
        return;
    }
    for (var i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getRowStatus(i) === "U") { //수정인 경우
            if (ds_out.getCellData(i, "cntrNo") == "" && (ds_out.getCellData(i, "dptHh").trim() != "" || ds_out.getCellData(i, "arvHh").trim() != "")) {
                $c.gus.cfAlertMsg((i + 1) + "번째 행에서 컨테이너번호가 없는 상태에서 출도착일시가 입력되었습니다");
                return;
            }

            if (ds_out.getCellData(i, "vehclNo") == "" && (ds_out.getCellData(i, "dptHh").trim() != "" || ds_out.getCellData(i, "arvHh").trim() != "")) {
                $c.gus.cfAlertMsg((i + 1) + "번째 행에서 차량배정이 안된 상태에서 출도착일시가 입력되었습니다");
                return;
            }

            if (ds_out.getCellData(i, "dptDt") != "" && ds_out.getCellData(i, "arvDt") != "") {
                if (scwin.cfDaysBetween(ds_out.getCellData(i, "dptDt"), ds_out.getCellData(i, "arvDt")) < 0) {
                    $c.win.alert((i + 1) + " 번째 열의 " + "컨테이너번호 " + ds_out.getCellData(i, "cntrNo") + " 의 상차일이 하차일보다 큽니다. 일자를 조정해 주십시오");
                    return false;
                }
                if (scwin.cfDaysBetween(ds_out.getCellData(i, "dptDt"), ds_out.getCellData(i, "arvDt")) == 0) {
                    if (ds_out.getCellData(i, "dptHh") != "" && ds_out.getCellData(i, "arvHh") != "") {
                        if (ds_out.getCellData(i, "arvHh") - ds_out.getCellData(i, "dptHh") < 0) {
                            $c.win.alert((i + 1) + " 번째 열의 " + "컨테이너번호 " + ds_out.getCellData(i, "cntrNo") + " 의 상차시간이 하차시간보다 큽니다. 시간을 조정해 주십시오");
                            return false;
                        }
                    }
                }
            }

            ds_out.setCellData(i, "orgCntrNo", ds_out.getOriginalCellData(i, "cntrNo"));
            ds_out.setCellData(i, "orgCntrSizCd", ds_out.getOriginalCellData(i, "cntrSizCd"));
            ds_out.setCellData(i, "orgCntrTypCd", ds_out.getOriginalCellData(i, "cntrTypCd"));
            ds_out.setCellData(i, "orgSealNo", ds_out.getOriginalCellData(i, "sealNo"));
            ds_out.setCellData(i, "orgDptDt", ds_out.getOriginalCellData(i, "dptDt"));
            ds_out.setCellData(i, "orgDptHh", ds_out.getOriginalCellData(i, "dptHh"));
            ds_out.setCellData(i, "orgArvDt", ds_out.getOriginalCellData(i, "arvDt"));
            ds_out.setCellData(i, "orgArvHh", ds_out.getOriginalCellData(i, "arvHh"));
            ds_out.setCellData(i, "orgChassisNo", ds_out.getOriginalCellData(i, "chassisNo"));
        }
    }

    if (scwin.f_rowDifferBetweenDate()) {
        return;
    }

    if (scwin.f_hourCheck()) {
        if (scwin.f_hourNullCheck()) {
            let confirm = await $c.win.confirm(MSG_CM_CRM_001);
            if (confirm) {
                //tr_saveEmp.Post();
                $c.sbm.execute(sbm_saveEmp);
            }
        }
    }
};

scwin.sbm_saveEmp_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        $c.gus.cfAlertMsg(MSG_CM_INF_001, [""]);
    }
};

scwin.cfDaysBetween = function (sDate, eDate) {

    sDate = sDate.trim();
    eDate = eDate.trim();

    //var validator1 = new covDateValidator("YYYYMMDD");
    //var validator2 = new covDateValidator("YYYYMMDD");

    if ($c.date.isDate(sDate) == false) {
        $c.win.alert("시작일자는 'YYYYMMDD' 형식이어야 합니다.");
        return;
    }

    if ($c.date.isDate(eDate) == false) {
        $c.win.alert("종료일자는 'YYYYMMDD' 형식이어야 합니다.");
        return;
    }

    var startDate = sDate.toDate("YYYYMMDD");
    var endDate = eDate.toDate("YYYYMMDD");

    return Math.floor((endDate - startDate) / 1000 / 60 / 60 / 24); // 밀리초/초/분/시간

};

//-------------------------------------------------------------------------
// Row 간 일자 체크 함수
//-------------------------------------------------------------------------
scwin.f_rowDifferBetweenDate = function () {
    var total_cnt = ds_out.getRowCount();
    var oldArvDt = "";
    var oldArvHh = "";
    var oldWrkStpCd = "";
    var j = 0;

    for (var i = 0; i < total_cnt; i++) {
        j = i - 1;

        if (i == 1) {
            if (ds_out.getCellData(i, "arvIoMgntYn") == 0) {
                oldArvDt = ds_out.getCellData(i, "arvDt");
                oldArvHh = ds_out.getCellData(i, "arvHh");
            } else if (ds_out.getCellData(i, "dptIoMgntYn") == 0) {
                oldArvDt = ds_out.getCellData(i, "dptDt");
                oldArvHh = ds_out.getCellData(i, "dptHh");
            } else {
                oldArvDt = "";
                oldArvHh = "";
            }

            oldWrkStpCd = ds_out.getCellData(i, "wrkStpCd");
            continue;
        }

        if (oldArvHh.trim() != "" && ds_out.getCellData(i, "dptHh").trim() != "") {
            if (ds_out.getRowStatus(i) === "U") {
                if (ds_out.getCellData(i, "wrkStpCd") != DsConstants.WRK_STP_CD_SHUTTLE
                    && ds_out.getCellData(i, "dptDt").trim() != ""
                    && ds_out.getCellData(i, "dptHh").trim() != ""
                    && oldArvDt.trim() != ""
                    && oldArvHh.trim() != ""
                    && (ds_out.getCellData(i, "dptDt").trim() + ds_out.getCellData(i, "dptHh").trim()) <= (oldArvDt.trim() + oldArvHh.trim())
                    && ds_out.getCellData(i, "cntrNo") == ds_out.getCellData(i - 1, "cntrNo")) {
                    $c.gus.cfAlertMsg(i + "번째 데이타에서 시작일시가 " + j + "번째 종료일시보다  이후 이어야 합니다.");
                    return true;
                }
            }
        }
        else {
            continue;
        }

        if (ds_out.getCellData(i, "arvIoMgntYn") == 0) {
            oldArvDt = ds_out.getCellData(i, "arvDt");
            oldArvHh = ds_out.getCellData(i, "arvHh");
        } else if (ds_out.getCellData(i, "dptIoMgntYn") == 0) {
            oldArvDt = ds_out.getCellData(i, "dptDt");
            oldArvHh = ds_out.getCellData(i, "dptHh");
        } else {
            oldArvDt = "";
            oldArvHh = "";
        }
    }
    return false;
};

//-------------------------------------------------------------------------
// 그리드 시간 체크 함수 hourCheck
//-------------------------------------------------------------------------
scwin.f_hourCheck = function () {

    return true;
    for (i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getRowStatus(i) === "U") {
            if (!$c.gus.cf_gidHourCheck(ds_out.getCellData(i, "dptHh"))) {
                ds_out.setRowPosition(i);
                //gr_out.ColSelect = "true";
                $c.gus.cfAlertMsg((i + 1) + "번째 출발시간을 정확한 시간을 입력하세요");
                //gr_out.SetColumn("dptHh");
                return false;
            }
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 그리드 시간 체크 함수 hourNullCheck
//-------------------------------------------------------------------------
scwin.f_hourNullCheck = function () {
    for (i = 0; i < ds_out.getRowCount(); i++) {
        if (ds_out.getRowStatus(i) === "U") {

            if (ds_out.getCellData(i, "arvHh") == "") {
                ds_out.setCellData(i, "arvDt", "");
            }
            if (ds_out.getCellData(i, "dptHh") == "") {
                ds_out.setCellData(i, "dptDt", "");
            }

            //dongwon-debis-engine/src/main/webapp/ds/common/script/dscommon.js
            if (!dscommon.cf_gidHourNullCheck(ds_out.getCellData(i, "arvHh"))) {
                ds_out.setRowPosition(i);
                //gr_out.ColSelect = "true";
                $c.gus.cfAlertMsg((i + 1) + "번째 도착시간을 정확한 시간을 입력하세요");
                //gr_out.SetColumn("arvHh");
                return false;
            }

        }
    }
    return true;
};

//-------------------------------------------------------------------------
// function name : f_crryInOutEDI(bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag))
// function desc : 반출입예정정보EDI등록
//-------------------------------------------------------------------------
scwin.btn_carryingInOutEDI_onclick = function (e) {
    if (ds_out.getRowCount() == 0) {
        return;
    }

    //f_crryInOutEDI(true, false, false, ds_out.RowPosition, false)
    let bAlertFlag = true;
    let row = ds_out.getRowPosition();
    if (ds_out.getCellData(row, "vehclNo") == "") {
        if (bAlertFlag) {
            $c.gus.cfAlertMsg("운송차량이 없습니다");
        }
        return false;
    }

    if (ds_out.getCellData(row, "crryinEdiFlag") == "N" && ds_out.getCellData(row, "crryoutEdiFlag") == "N") {
        if (bAlertFlag) {
            $c.gus.cfAlertMsg("EDI등록 대상이 아닙니다");
        }
        return false;
    }

    var rtnList = new Array();
    var arrParam = new Array();
    arrParam[0] = new Array( ""				// 조회구분 ("" : 운송작업지시, "1" : 반출입)
                            , ds_out.getCellData(row, "transWrkIndictNo")
                            , ds_out.getCellData(row, "odrNo")
                            , ds_out.getCellData(row, "cntrSeq")
                            , ds_out.getCellData(row, "wrkPathSeq")
                            , ds_out.getCellData(row, "wrkStpSeq")
                            , ds_out.getCellData(row, "vehclShortCd")
                            , ds_out.getCellData(row, "vehclNo")
                            , ds_out.getCellData(row, "vehclIdCardNo")
                            , ds_out.getCellData(row, "wrkStDtm")
                            , ds_out.getCellData(row, "wrkEndDtm")
                            , ds_out.getCellData(row, "cntrNo")
                            , ds_out.getCellData(row, "dptWrkPlCd")
                            , ds_out.getCellData(row, "arvWrkPlCd")
                            , ds_out.getCellData(row, "dptWrkPlCdNm")
                            , ds_out.getCellData(row, "arvWrkPlCdNm")
                            , ds_out.getCellData(row, "crryoutEdiType")
                            , ds_out.getCellData(row, "crryinEdiType")
                            );
    var data = {
        crryoutEdiType: ds_out.getCellData(row, "crryoutEdiType")
        , crryinEdiType: ds_out.getCellData(row, "crryinEdiType")
        , callbackFn: scwin.f_crryInOutEDI_callBackFunc
    };
    data.arrParam = arrParam;

    var opts = {
        id: "smpPop"
        , popupName: "반출입예정정보EDI등록"
        , modal: true
        , type: "browserPopup"  //화면 오픈 타입 ("pageFramePopup", "browserPopup")
        , title: "Win pop"  //Layer pop
        , width: 850
        , height: 750
    };

    $c.win.openPopup("/ui/ds/op/wrkplan/transwrkplan/op_202_02_23p.xml", opts, data);
};


//-------------------------------------------------------------------------
// Popup 처리 : 그리드에서 입력된 코드정보 조회
//-------------------------------------------------------------------------
scwin.f_openCommPopUpGrid = function (disGubun, row, pClose) {
    if (isPopupOpen) return; // 팝업이 이미 열려있으면 함수 종료 (중복 방지)        

    isPopupOpen = true;
    // 선언부
    var rtnList;  // 공통POP-UP -> 요청화면 
    var pCode = "";
    var pName = "";
    var colNm = new Array();

    if (disGubun == "1") {
        colNm[0] = "cntrSizCd";
        colNm[1] = "cntrTypCd";
        colNm[2] = "fullEmptyClsCd";
        pCode = ds_out.getCellData(row, "cntrNo");
        pName = ds_out.getCellData(row, "odrNo");                               	//data;
        pWhere = ds_out.getCellData(row, "cntrSeq") + "," + ds_out.getCellData(row, "odrNo");
        //pClose = "T";
        pAllSearch = "F";
        udc_comCodeGrid.setSelectId('retrieveConteinerNo');
        udc_comCodeGrid.cfCommonPopUp(scwin.udc_comCodeGrid1_callBackFunc	        // XML상의 SELECT ID	
            , pCode					// 화면에서의 ??? Code Element의	Value
            , pName					// 화면에서의 ??? Name Element의	Value
            , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
            , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
            , null					// Title순서	
            , null					// 보여주는 각 컬럼들의 폭	
            , null					// 컬럼중에서 숨기는	컬럼 지정	
            , pWhere					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
            , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
            , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
            , null					// 윈도우 위치 Y좌표	
            , null					// 윈도우 위치 X좌표
            , null					// 중복체크여부	("F")
            , pAllSearch					// 전체검색허용여부	("F")
            //,"컨테이너,컨테이너번호,,규격,F/E"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );
    }
    else if (disGubun == "2") {
        pCode = ds_out.getCellData(row, "chassisNo");
        pName = "";
        //pClose = "T";
        pAllSearch = "F";
        udc_comCodeGrid.setSelectId('retrieveChassis');
        udc_comCodeGrid.cfCommonPopUp(scwin.udc_comCodeGrid2_callBackFunc	        // XML상의 SELECT ID	
            , pCode					// 화면에서의 ??? Code Element의	Value
            , pName					// 화면에서의 ??? Name Element의	Value
            , pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
            , null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
            , null					// Title순서	
            , null					// 보여주는 각 컬럼들의 폭	
            , null					// 컬럼중에서 숨기는	컬럼 지정	
            , null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
            , null					// POP-UP뛰을때 원도우의	사용자 정의	폭
            , null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
            , null					// 윈도우 위치 Y좌표	
            , null					// 윈도우 위치 X좌표
            , null					// 중복체크여부	("F")
            , pAllSearch					// 전체검색허용여부	("F")
            , "샤시번호,단축코드,샤시번호"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
        );

    }
    isPopupOpen = false;
};

scwin.udc_comCodeGrid1_callBackFunc = function (rtnList) {

    //cfSetGridReturnValue(rtnList, ds_out, row, "cntrNo", "", colNm);
    let row = ds_out.getRowPosition();
    ds_out.setCellData(row + 1, "cntrNo", ds_out.getCellData(row, "cntrNo"));

    if (rtnList != null) {
        if (rtnList[0] != "N/A") {
            if (ds_out.getCellData(row, "lineCd") != rtnList[6]) {
                $c.win.alert("오더LINE = " + ds_out.getCellData(row, "lineCd") + " // 컨테이너LINE = " + rtnList[6] + " 컨테이너와 오더의 LINE이 불일치합니다.");
                ds_out.setCellData(row, "cntrNo", "");
                return false;
            }

            ds_out.setCellData(row, "cntrNo", rtnList[0]);
            ds_out.setCellData(row, "cntrSizCd", rtnList[2]);
            ds_out.setCellData(row, "cntrTypCd", rtnList[3]);
            // ds_out.setCellData(row, "fullEmptyClsCd", rtnList[4]);
            ds_out.setCellData(row, "arrvlportDtm", rtnList[5]);

            var vOdrNo = ds_out.getCellData(row, "odrNo");
            var vCntrSeq = ds_out.getCellData(row, "cntrSeq");
            for (var i = 0; i < ds_out.getRowCount(); i++) {
                if (i != row) {
                    if (vOdrNo == ds_out.getCellData(i, "odrNo") && vCntrSeq == ds_out.getCellData(i, "cntrSeq")) {
                        ds_out.setCellData(i, "cntrNo", rtnList[0]);
                        ds_out.setCellData(i, "cntrSizCd", rtnList[2]);
                        ds_out.setCellData(i, "cntrTypCd", rtnList[3]);
                        ds_out.setCellData(i, "arrvlportDtm", rtnList[5]);
                    }
                }
            }//for
        }
    }
};

