                    if (!dscommon.cf_CheckCntrNo(ds_out.getCellData(row, "cntrNo"))) {
                        let confirm = await $c.win.confirm(row + "번째 컨테이너 번호는 유효하지 않은 컨테이너입니다. 계속진행하시겠습니까?");
                        if (!confirm) {
                            return;
                        }
                    }
