                    && ds_out.getCellData(row + 1, "cntrSeq") == ds_out.getCellData(row, "cntrSeq")) {
                    ds_out.setCellData(row + 1, "sealNo", ds_out.getCellData(row, "sealNo"));
                }
                break;
            default:
                break;
        }
