};

//-------------------------------------------------------------------------
// 할인할증등록
//-------------------------------------------------------------------------
scwin.btn_dcsn_onclick = function (e) {
    var row = ds_out.getRowPosition();
    var len = ds_out.getCellData(row, "vehclNo").length;

    let src = "/ui/ds/op/wrkrslts/transwrkrslts/op_304_03_01b.xml";
    let menuNm = "운송할인할증등록";
    let menuId = "11111";

    paramObj = {};
    paramObj = {
        transWrkIndictNo: ds_out.getCellData(row, "transWrkIndictNo")
        , lobranCd: ds_out.getCellData(row, "wrkLobranCd")
        , wrkStDt: ds_out.getCellData(row, "dptDt")
        , vehclNo: ds_out.getCellData(row, "vehclNo")
        , vehclNoCd: ds_out.getCellData(row, "vehclNo").substring(len - 4, len)
        , eqCd: ds_out.getCellData(row, "eqCd")
    };

    if (ds_out.getRowCount() < 1) {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002, [""]);
        return;
    }

    $c.win.openMenu(menuNm, src, menuId, paramObj);
};

scwin.btn_cancel_onclick = function (e) {
    var row = ds_out.getRowPosition();
    let keepData = ds_out.getCellData(row, "cntrTypCdInfo"); // 1. 남길 데이터 미리 백업
    ds_out.undoRow(row);
    ds_out.setCellData(row, "cntrTypCdInfo", keepData); // 3. 백업했던 데이터 다시 세팅

};

// data: 해당 셀의 원래 들어있는 데이터 (예: "Error", "Success" 등)
scwin.fmt_mobileErr = function (data, formattedData, rowIndex, colIndex) {

    // 데이터가 "Error"면 "E"를 리턴, 아니면 "N"을 리턴
    if (data === "Error") {
        return "E";
    } else {
        return "N";
    }
};

