 * 한글방지 & 대문자만
 */
scwin.regFilter = function(e) {
    var val = e.target.value;
    // 영문 + 숫자만 남기기
    val = val.replace(/[^a-zA-Z0-9]/g, "");

    // 영문은 대문자로 변환
    val = val.toUpperCase();
    this.setValue(val);
};
